import{_ as e,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"别嫔","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/别嫔.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/别嫔.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/别嫔.md"};function b(l,a,i,p,_,c){return t(),n("div",null,[...a[0]||(a[0]=[r("h1",{id:"别嫔",tabindex:"-1"},[s("别嫔 "),r("a",{class:"header-anchor",href:"#别嫔","aria-label":'Permalink to "别嫔"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌034")])])],-1),o('<h1 id="别嫔-1" tabindex="-1">别嫔 <a class="header-anchor" href="#别嫔-1" aria-label="Permalink to &quot;别嫔&quot;">​</a></h1><p>别嫔<br> A+4000<br> 这是一柄形如皎月的日式太刀，寄宿着一位痴情男子的爱意与……无数忍者的仇怨因果。<br> 这柄剑是初服部忍者为杀死自己的师傅、所有忍者的源头——无敌、无敌、无敌的胜·万松而秘密委托雷匠忍者所打造。<br> 尽管背叛忍者之祖是十恶不赦之大罪，但雷匠忍者却义无反顾的接下了这一任务。他以自身精湛超绝、亦被无敌、无敌、无敌的忍者之祖—胜·万松所称赞的技艺结合以无敌、无敌、无敌的忍者之祖—胜·万松的指骨为核心铸造了此剑，并以他心爱的女人—服部忍者之女的名字为这柄剑命名。<br> 于是，服部忍者与刃铁凭借此剑对无敌、无敌、无敌的忍者之祖—胜·万松发起反叛，最终令其殒命。<br> 【选开】：在忍杀世界观中，这一柄剑无法被剑身上雕出名号或Clan的忍者所毁坏。</p><p>武器伤害：28L<br> 武器类型：太刀<br> 武器体积：3<br> 使用专业：剑/刀<br> 特性：<br> 【封魂铭刻】：这把剑的剑身上铭刻着数不清的名字，它们来自于忍杀星上几乎所有的忍者，从知名的24个Clan到名气微末的忍者无不在此列。当然，也包括无敌、无敌、无敌的忍者之祖—胜·万松。（注：奈落与杀伐骑士除外）<br> 以此武器进行攻击时，若对方的名号或者流派被铭刻在剑身上，则额外获得20点破甲；当对方被此武器杀死，你可以将其灵魂吸入剑身，使其无法以S级及以下的能力进行复活。<br> 角色可以在合适的场景（具有锻炉或者类似的物品）中花费时间以一小时为周期对这把剑进行造物检定，当合计成功数达到38后即可在此剑刃上刻下新的名号或流派。<br> 【如梦似幻】：使用此武器进行攻击时，使用者可以敏捷+武技+剑/刀进行一个检定，被攻击单位需要进行感知+洞察+侦查检定以对抗，若对方对抗失败，则其将无法看清别嫔的剑刃，在应对此次攻击时将因此而受到A级别措手不及效果。<br> 【斩舍·御免】：据传黑暗忍者以这把武器杀死了无敌、无敌、无敌的忍者之祖—胜·万松。而至最后，黑暗忍者自身也被这把武器杀死，这一式即为黑暗忍者的忍魂中所残留的技艺。<br> 以整轮动作使用，在周身挥舞剑刃令其偏折空间以遮蔽身形，人物在一轮内获得A级别、特异本质的反侦测等级，在此期间人物进行侦测检定对抗时，可以武技+剑/刀替代隐秘+潜藏进行检定。<br> 在这一轮内，人物可以反射动作打断性的进行一次冲锋攻击，这次冲锋攻击不会承受基础防御减值，在进行冲锋移动时具有A级别、幻像来源的传送效果。<br> 若你冲锋的对象不具有你的任何定位等级，此次冲锋还将具有S级措手不及效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=e(d,[["render",b]]);export{f as __pageData,m as default};
